function copyBuildLogs(btn) {
  const pre = btn.closest("div").parentElement.querySelector(".build-log-output") || document.querySelector(".build-log-output");
  if (!pre) return;
  navigator.clipboard.writeText(pre.textContent).then(() => {
    btn.textContent = "Copied!";
    setTimeout(() => { btn.textContent = "Copy Logs"; }, 2000);
  });
}

async function showFailedBuildLog(siteName, buildId) {
  const area = document.getElementById("failedBuildLogArea");
  if (!area) return;
  area.innerHTML = `<div class="deploy-step active" style="margin:0.5rem 0"><div class="spinner"></div><span>Loading build log...</span></div>`;
  try {
    const result = await api("GET", `/sites/${siteName}/container/build/${encodeURIComponent(buildId)}`);
    const logs = result.build_logs || "";
    if (logs) {
      area.innerHTML = `
        <pre class="build-log-output">${esc(logs)}</pre>
        <div style="margin:0.5rem 0"><button class="btn btn-ghost btn-sm" onclick="copyBuildLogs(this)">Copy Logs</button></div>
      `;
    } else {
      area.innerHTML = `<p style="font-size:0.85rem;color:var(--text-dim);margin:0.5rem 0">No build logs available.</p>`;
    }
  } catch (err) {
    area.innerHTML = `<p style="font-size:0.85rem;color:var(--danger);margin:0.5rem 0">Failed to load build log: ${esc(err.message)}</p>`;
  }
}

