"/api/sites/{siteName}/upload": {
  "post": {
    "operationId": "getWebsiteUploadUrl",
    "summary": "Get presigned URL for website ZIP upload",
    "description": "Returns a presigned S3 URL valid for 1 hour. Upload a ZIP containing your static website files (index.html, etc.) using an HTTP PUT to the returned URL. After uploading, call deployWebsite to extract and deploy.",
    "parameters": [
      {
        "name": "siteName",
        "in": "path",
        "required": true,
        "schema": { "type": "string" },
        "description": "The unique site name"
      }
    ],
    "responses": {
      "200": {
        "description": "Presigned upload URL",
        "content": {
          "application/json": {
            "schema": { "$ref": "#/components/schemas/UploadUrlResponse" }
          }
        }
      }
    }
  }
},
"/api/sites/{siteName}/deploy": {
  "post": {
    "operationId": "deployWebsite",
    "summary": "Deploy website from uploaded ZIP",
    "description": "Extracts the previously uploaded ZIP and deploys the static files to the S3 hosting bucket. The site becomes available at its hostname. Call getWebsiteUploadUrl first and upload the ZIP before calling this.",
    "parameters": [
      {
        "name": "siteName",
        "in": "path",
        "required": true,
        "schema": { "type": "string" },
        "description": "The unique site name"
      }
    ],
    "responses": {
      "200": {
        "description": "Deployment result",
        "content": {
          "application/json": {
            "schema": { "$ref": "#/components/schemas/WebsiteDeployResponse" }
          }
        }
      }
    }
  }
},
"/api/sites/{siteName}/container/upload": {
  "post": {
    "operationId": "getContainerUploadUrl",
    "summary": "Get presigned URL for container source ZIP upload",
    "description": "Returns a presigned S3 URL valid for 1 hour. Upload a ZIP containing your container source code (with a Dockerfile, or source files for manifest-based builds) using an HTTP PUT to the returned URL. After uploading, call buildFromDockerfile or buildFromManifest.",
    "parameters": [
      {
