        "in": "path",
        "required": true,
        "schema": { "type": "string" },
        "description": "The unique site name"
      }
    ],
    "responses": {
      "200": {
        "description": "Presigned upload URL",
        "content": {
          "application/json": {
            "schema": { "$ref": "#/components/schemas/ContainerUploadUrlResponse" }
          }
        }
      }
    }
  }
},
"/api/sites/{siteName}/container/build-dockerfile": {
  "post": {
    "operationId": "buildFromDockerfile",
    "summary": "Build container from uploaded ZIP with Dockerfile",
    "description": "Triggers a CodeBuild build using the previously uploaded source ZIP which must contain a Dockerfile. The build pushes the image to ECR and auto-deploys on success. Poll getBuildStatus to track progress. Call getContainerUploadUrl first and upload the ZIP before calling this.",
    "parameters": [
      {
        "name": "siteName",
        "in": "path",
        "required": true,
        "schema": { "type": "string" },
        "description": "The unique site name"
      }
    ],
    "requestBody": {
      "required": false,
      "content": {
        "application/json": {
          "schema": { "$ref": "#/components/schemas/ContainerBuildOptions" }
        }
      }
    },
    "responses": {
      "200": {
        "description": "Build initiated",
        "content": {
          "application/json": {
            "schema": { "$ref": "#/components/schemas/BuildResponse" }
          }
        }
      }
    }
  }
},
